import React, { createContext, useContext, useState, useEffect, useCallback } from 'react';

const AuthContext = createContext(null);
const BASE_URL = process.env.REACT_APP_API_URL || 'http://localhost:5000';

// ── API helpers ───────────────────────────────────────────────────────────────

function getToken() {
  const saved = localStorage.getItem('wc_user');
  if (saved) {
    try { return JSON.parse(saved).token; } catch(e) {}
  }
  return null;
}

async function apiLogin(payload) {
  const res = await fetch(`${BASE_URL}/api/login`, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify(payload),
  });
  if (!res.ok) {
    const err = await res.json().catch(() => ({}));
    throw new Error(err.message || 'Invalid credentials');
  }
  return res.json();
}

async function apiFetchUsers() {
  const res = await fetch(`${BASE_URL}/api/users`, {
    headers: {
      'Authorization': `Bearer ${getToken()}`
    }
  });
  if (!res.ok) throw new Error('Failed to fetch users');
  return res.json();
}

// ── Provider ──────────────────────────────────────────────────────────────────

export function AuthProvider({ children }) {
  // Restore session from localStorage so page refresh keeps user logged in
  const [user, setUser] = useState(() => {
    const saved = localStorage.getItem('wc_user');
    return saved ? JSON.parse(saved) : null;
  });

  // Users are loaded from backend, not localStorage
  const [users, setUsers] = useState([]);

  // ── Load all users from backend on mount ──────────────────────────────────
  const refreshUsers = useCallback(async () => {
    // Only admins need to fetch the full participant list for the analytics dashboard
    if (!user || !user.isAdmin) return;
    try {
      const data = await apiFetchUsers();
      setUsers(data);
    } catch (err) {
      console.error('Failed to load users:', err);
    }
  }, [user]);

  useEffect(() => { refreshUsers(); }, [refreshUsers]);

  // ── Login ─────────────────────────────────────────────────────────────────
  const login = async (identifier, password) => {
    const trimId = identifier.trim();
    const trimPass = password.trim();

    if (!trimId || !trimPass) {
      return { success: false, error: 'Please enter all fields' };
    }

    try {
      const payload = { identifier: trimId, password: trimPass };
      const sessionUser = await apiLogin(payload);
      setUser(sessionUser);
      localStorage.setItem('wc_user', JSON.stringify(sessionUser));
      return { success: true };
    } catch (err) {
      return { success: false, error: err.message };
    }
  };

  // ── Logout ────────────────────────────────────────────────────────────────
  const logout = () => {
    setUser(null);
    localStorage.removeItem('wc_user');
  };

  return (
    <AuthContext.Provider value={{ user, users, login, logout, refreshUsers }}>
      {children}
    </AuthContext.Provider>
  );
}

export const useAuth = () => useContext(AuthContext);
