import React, { useState } from 'react';
import { useMatches } from '../context/MatchContext';
import './TeamsPage.css';

export default function TeamsPage() {
  const { teams, matches } = useMatches();
  const [view, setView] = useState('grid'); // grid | group
  const [search, setSearch] = useState('');
  const [selectedTeam, setSelectedTeam] = useState(null);

  const GROUPS = [...new Set((teams || []).map(t => t.group))].sort();

  const filtered = (teams || []).filter(t =>
    t.name.toLowerCase().includes(search.toLowerCase())
  );

  // Compute team statistics
  const getTeamStats = (teamName) => {
    const teamMatches = (matches || []).filter(m => m.teamA?.name === teamName || m.teamB?.name === teamName);
    const playedMatches = teamMatches.filter(m => m.status === 'completed');
    
    let w = 0, d = 0, l = 0;
    let gf = 0, ga = 0;
    let cs = 0;
    
    playedMatches.forEach(m => {
      const isTeamA = m.teamA.name === teamName;
      const myScore = isTeamA ? m.scoreA : m.scoreB;
      const oppScore = isTeamA ? m.scoreB : m.scoreA;
      
      gf += myScore || 0;
      ga += oppScore || 0;
      if (oppScore === 0) cs++;

      // Penalty check for win/loss
      if (myScore > oppScore) { w++; }
      else if (myScore < oppScore) { l++; }
      else {
        if (m.resultType === 'PSO' && m.penaltyA !== null && m.penaltyB !== null) {
          const myPen = isTeamA ? m.penaltyA : m.penaltyB;
          const oppPen = isTeamA ? m.penaltyB : m.penaltyA;
          if (myPen > oppPen) w++;
          else if (myPen < oppPen) l++;
          else d++;
        } else {
          d++;
        }
      }
    });

    const isEliminated = l > 0; // In knockout tournament, 1 loss = eliminated
    
    return {
      played: playedMatches.length,
      w, d, l, gf, ga, gd: gf - ga, cs,
      history: teamMatches,
      status: isEliminated ? 'Eliminated' : playedMatches.length > 0 ? 'Active' : 'Upcoming'
    };
  };

  return (
    <div className="page teams-page">
      <div className="page-header">
        <div>
          <h2 className="page-title">COMPETING TEAMS</h2>
          <p className="page-sub">Round of 32 — {(teams || []).length} nations qualified</p>
        </div>
      </div>

      <div className="teams-controls">
        <input
          className="team-search"
          placeholder="🔍  Search teams..."
          value={search}
          onChange={e => setSearch(e.target.value)}
        />
        <div className="view-toggle">
          <button className={view === 'grid' ? 'active' : ''} onClick={() => setView('grid')}>Grid</button>
          <button className={view === 'group' ? 'active' : ''} onClick={() => setView('group')}>By Group</button>
        </div>
      </div>

      {view === 'grid' ? (
        <div className="teams-grid">
          {filtered.map((t, i) => {
            const stats = getTeamStats(t.name);
            return (
              <TeamCard 
                key={t.name} 
                team={t} 
                stats={stats}
                delay={i} 
                onClick={() => setSelectedTeam({ ...t, stats })} 
              />
            );
          })}
        </div>
      ) : (
        <div className="groups-view" style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(280px, 1fr))', gap: '1.5rem' }}>
          {GROUPS.map(g => {
            const groupTeams = filtered.filter(t => t.group === g);
            if (groupTeams.length === 0) return null;
            return (
              <div key={g} className="group-section" style={{ background: 'rgba(20,30,50,.5)', padding: '1.5rem', borderRadius: '12px', border: '1px solid rgba(255,255,255,0.06)' }}>
                <div className="group-header" style={{ fontSize: '1.1rem', fontWeight: '800', borderBottom: '1px solid rgba(245,197,24,.2)', paddingBottom: '.5rem', marginBottom: '1rem', color: '#f5c518', letterSpacing: '.06em' }}>GROUP {g}</div>
                <div style={{ display: 'flex', flexDirection: 'column', gap: '.65rem' }}>
                  {groupTeams.map((t) => (
                    <div 
                      key={t.name} 
                      className="group-team-item"
                      onClick={() => setSelectedTeam({ ...t, stats: getTeamStats(t.name) })}
                    >
                      <span style={{ fontSize: '1.4rem' }}>{t.flag}</span>
                      <strong style={{ fontWeight: '600' }}>{t.name}</strong>
                    </div>
                  ))}
                </div>
              </div>
            );
          })}
        </div>
      )}

      {selectedTeam && (
        <TeamProfileModal team={selectedTeam} onClose={() => setSelectedTeam(null)} />
      )}
    </div>
  );
}

function TeamCard({ team, stats, delay, onClick }) {
  const winRate = stats.played > 0 ? (stats.w / stats.played) * 100 : 0;

  return (
    <div className="team-card fade-in interactive-card" style={{ animationDelay: `${delay * 0.04}s` }} onClick={onClick}>
      <div className="tc-flag">{team.flag}</div>
      <div className="tc-name">{team.name}</div>
      <div className="tc-group">Group {team.group}</div>
      
      <div className="tc-stats">
        <div className="tc-stat"><span>{stats.played}</span><label>PLD</label></div>
        <div className="tc-stat"><span>{stats.w}</span><label>W</label></div>
        <div className="tc-stat"><span>{stats.d}</span><label>D</label></div>
        <div className="tc-stat"><span>{stats.l}</span><label>L</label></div>
      </div>
      
      <div className="tc-goals">
        <span>GF: {stats.gf}</span>
        <span className="tc-gd">GD {stats.gd > 0 ? `+${stats.gd}` : stats.gd}</span>
        <span>GA: {stats.ga}</span>
      </div>
      
      <div className="tc-winbar-wrap">
        <div className="tc-winbar" style={{ width: `${winRate}%` }}></div>
      </div>
      <span className="tc-winrate">Win Rate: {winRate.toFixed(0)}%</span>

      <div className="tc-hover-hint">View Profile</div>
    </div>
  );
}

function TeamProfileModal({ team, onClose }) {
  const { stats } = team;
  
  return (
    <div className="confirm-overlay" onClick={onClose}>
      <div className="tp-modal fade-in" onClick={e => e.stopPropagation()}>
        <button className="tp-close" onClick={onClose}>×</button>
        
        <div className="tp-header">
          <div className="tp-flag">{team.flag}</div>
          <div className="tp-title-area">
            <h2>{team.name}</h2>
            <span className={`tp-status ${stats.status.toLowerCase()}`}>{stats.status}</span>
          </div>
        </div>

        <div className="tp-stats-grid">
          <div className="tp-stat">
            <span className="tp-stat-val">{stats.played}</span>
            <span className="tp-stat-label">Played</span>
          </div>
          <div className="tp-stat">
            <span className="tp-stat-val">{stats.w}-{stats.d}-{stats.l}</span>
            <span className="tp-stat-label">W-D-L</span>
          </div>
          <div className="tp-stat">
            <span className="tp-stat-val">{stats.gf}</span>
            <span className="tp-stat-label">Goals For</span>
          </div>
          <div className="tp-stat">
            <span className="tp-stat-val">{stats.cs}</span>
            <span className="tp-stat-label">Clean Sheets</span>
          </div>
        </div>

        <div className="tp-history">
          <h3>Match History</h3>
          {stats.history.length === 0 && <div className="tp-no-matches">No matches scheduled yet.</div>}
          <div className="tp-match-list">
            {stats.history.map(m => {
              const isTeamA = m.teamA.name === team.name;
              return (
                <div key={m.id} className={`tp-match-row ${m.status}`}>
                  <div className="tp-match-date">{new Date(m.date).toLocaleDateString('en-GB', { day: 'numeric', month: 'short' })}</div>
                  <div className="tp-match-teams">
                    <span className={isTeamA ? 'tp-bold' : ''}>{m.teamA.flag} {m.teamA.code}</span>
                    <span className="tp-score">{m.status === 'completed' ? `${m.scoreA} - ${m.scoreB}` : 'vs'}</span>
                    <span className={!isTeamA ? 'tp-bold' : ''}>{m.teamB.code} {m.teamB.flag}</span>
                  </div>
                  <div className="tp-match-status">{m.status === 'completed' ? 'FT' : m.status === 'live' ? 'LIVE' : m.round}</div>
                </div>
              )
            })}
          </div>
        </div>
      </div>
    </div>
  );
}
