export default function LoginPage() {
  const { login } = useAuth();
  const navigate = useNavigate();
  const [form, setForm] = useState({ identifier: '', password: '' });
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);
  const [showPassword, setShowPassword] = useState(false);

  const handleChange = e => {
    setForm(f => ({ ...f, [e.target.name]: e.target.value }));
    setError('');
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    setError('');
    await new Promise(r => setTimeout(r, 380));

    const result = await login(form.identifier, form.password);

    if (result.success) {
      navigate('/predict');
    } else {
      setError(result.error);
    }
    setLoading(false);
  };

  return (
    <div className="lp-root">
      <div className="lp-bg">
        <div className="lp-bg-circle c1" />
        <div className="lp-bg-circle c2" />
        <div className="lp-bg-circle c3" />
        <div className="lp-field-lines" />
      </div>

      <div className="lp-container">
        {/* ── Left hero panel ── */}
        <div className="lp-hero">
          <div className="lp-hero-inner">
            <div className="lp-brand">
              {/* College Branding Section */}
              <div className="lp-college-branding">
                <div className="lp-logo-placeholder">
                  <img src={process.env.PUBLIC_URL + '/college_logo.jpeg'} alt="College Logo" className="lp-college-img" />
                </div>
                <p>Department of Computer Application (Aided)</p>
              </div>

              <div className="lp-brand-badge">⚽</div>
              <h1 className="lp-brand-title">FIFA<br/><span>WORLD CUP</span></h1>
              <p className="lp-brand-sub">PREDICTION LEAGUE</p>
            </div>
            <div className="lp-stats-row">
              <div className="lp-stat"><span>32</span><em>Teams</em></div>
              <div className="lp-stat-divider"/>
              <div className="lp-stat"><span>32</span><em>Matches</em></div>
              <div className="lp-stat-divider"/>
              <div className="lp-stat"><span>6</span><em>Stages</em></div>
            </div>
          </div>
        </div>

        {/* ── Right auth panel ── */}
        <div className="lp-auth-panel">
          <div className="lp-card">

            <div className="lp-panels-wrap">
              <div className="lp-panels show-student">
                <div className="lp-panel">
                  <div className="lp-form-headline">
                    <div className="lp-login-icon">🌍</div>
                    <h2>Login to Predict</h2>
                    <p>Enter your admission number and password</p>
                  </div>
                  <form onSubmit={handleSubmit} className="lp-form">
                    <div className="lp-field">
                      <label>ADMISSION NO / USERNAME</label>
                      <div className="lp-input-wrap">
                        <span className="lp-input-icon">👤</span>
                        <input
                          name="identifier"
                          value={form.identifier}
                          onChange={handleChange}
                          required
                          autoComplete="username"
                        />
                      </div>
                    </div>
                    <div className="lp-field">
                      <label>PASSWORD</label>
                      <div className="lp-input-wrap">
                        <span className="lp-input-icon">🔑</span>
                        <input
                          name="password"
                          type={showPassword ? "text" : "password"}
                          value={form.password}
                          onChange={handleChange}
                          placeholder="Enter your password"
                          required
                          autoComplete="current-password"
                        />
                        <button 
                          type="button" 
                          className="lp-toggle-password" 
                          onClick={() => setShowPassword(!showPassword)}
                          aria-label={showPassword ? "Hide password" : "Show password"}
                        >
                          {showPassword ? "👁️‍🗨️" : "👁️"}
                        </button>
                      </div>
                    </div>
                    {error && (
                      <div className="lp-error"><span>⚠️</span> {error}</div>
                    )}
                    <button className="lp-submit lp-submit--student" type="submit" disabled={loading}>
                      {loading
                        ? <span className="lp-spinner"/>
                        : <>Enter the Arena <span className="lp-arrow">→</span></>}
                    </button>
                  </form>
                </div>
              </div>
            </div>

          </div>
        </div>
      </div>
    </div>
  );
}
