import React, { useState } from 'react';
import { useMatches } from '../context/MatchContext';
import { useAuth } from '../context/AuthContext';
import './AdminPage.css';

const BASE_URL = process.env.REACT_APP_API_URL || 'http://localhost:5000';

const ROUND_ORDER = ['Round of 32', 'Round of 16', 'Quarter-Final', 'Semi-Final', '3rd Place', 'Final'];

const FLAGS = ['🇦🇷','🇧🇷','🇫🇷','🇩🇪','🇪🇸','🇵🇹','🏴󠁧󠁢󠁥󠁮󠁧󠁿','🇳🇱','🇺🇸','🇲🇽','🇯🇵','🇰🇷','🇸🇳','🇲🇦','🇺🇾','🇵🇱','🇨🇭','🇧🇪','🇭🇷','🇩🇰','🇸🇪','🇦🇹','🇪🇨','🇨🇦','🇦🇺','🏆','🥉'];

const VENUES = [
  'MetLife Stadium, New York/New Jersey',
  'AT&T Stadium, Dallas',
  'Arrowhead Stadium, Kansas City',
  'NRG Stadium, Houston',
  'Mercedes-Benz Stadium, Atlanta',
  'SoFi Stadium, Los Angeles',
  'Lincoln Financial Field, Philadelphia',
  'Lumen Field, Seattle',
  "Levi's Stadium, San Francisco",
  'Gillette Stadium, Boston',
  'Hard Rock Stadium, Miami',
  'BC Place, Vancouver',
  'BMO Field, Toronto',
  'Estadio Azteca, Mexico City',
  'Estadio BBVA, Monterrey',
  'Estadio Akron, Guadalajara',
];

export default function AdminPage() {
  const { matches, saveMatch, addMatch, resetMatches, loading, teams, saveTeam, addTeam, deleteTeam } = useMatches();
  const { users } = useAuth();
  const [activeTab, setActiveTab] = useState('scores');
  const [activeRound, setActiveRound] = useState('Round of 32');
  const [editing, setEditing] = useState({});
  const [saved, setSaved] = useState({});
  const [confirmReset, setConfirmReset] = useState(false);
  const [toast, setToast] = useState(null);
  const [saving, setSaving] = useState({});

  // Team management state
  const [editingTeam, setEditingTeam] = useState(null);
  const [teamError, setTeamError] = useState('');
  const [teamSaving, setTeamSaving] = useState(false);
  const [newTeam, setNewTeam] = useState({ name: '', flag: '🏆', group: 'A' });
  const [confirmDeleteTeam, setConfirmDeleteTeam] = useState(null);

  // Insights state
  const [insights, setInsights] = useState(null);
  const [loadingInsights, setLoadingInsights] = useState(false);

  // Add Match form
  const emptyMatch = { round: 'Round of 32', date: '', time: '18:00', venue: VENUES[0], teamAName: '', teamAFlag: '🏆', teamBName: '', teamBFlag: '🏆', matchNum: '' };
  const [newMatch, setNewMatch] = useState(emptyMatch);
  const [matchError, setMatchError] = useState('');
  const [matchAdding, setMatchAdding] = useState(false);

  const showToast = (msg, type = 'success') => {
    setToast({ msg, type });
    setTimeout(() => setToast(null), 2500);
  };

  const handleViewInsights = async (match) => {
    setLoadingInsights(true);
    setInsights(null);
    try {
      const user = JSON.parse(localStorage.getItem('wc_user') || '{}');
      const res = await fetch(`http://localhost:5000/api/predictions/match-stats/${match.id}`, {
        headers: { 'Authorization': `Bearer ${user.token}` }
      });
      if (!res.ok) {
        const text = await res.text();
        throw new Error(`Error ${res.status}: ${text}`);
      }
      const data = await res.json();
      setInsights({ match, data });
    } catch (err) {
      showToast(err.message, 'warn');
    } finally {
      setLoadingInsights(false);
    }
  };

  // ── SCORES TAB ──
  const handleEdit = (id, field, val) => setEditing(e => ({ ...e, [id]: { ...(e[id] || {}), [field]: val } }));
  const getVal = (match, field) => {
    if (editing[match.id] && editing[match.id][field] !== undefined) return editing[match.id][field];
    return match[field] ?? '';
  };

  const handleSave = async (match) => {
    const edits = editing[match.id] || {};
    const merged = { ...match, ...edits };
    const resultType = merged.resultType ?? match.resultType ?? '90min';
    const penA = merged.penaltyA ?? match.penaltyA;
    const penB = merged.penaltyB ?? match.penaltyB;
    const sA   = merged.scoreA ?? match.scoreA;
    const sB   = merged.scoreB ?? match.scoreB;

    // ── Validation ──────────────────────────────────────────────────────
    // PSO requires penalty scores
    if (resultType === 'PSO') {
      if (penA === null || penA === undefined || penA === '') {
        showToast('Enter penalty scores for both teams!', 'warn'); return;
      }
      if (penB === null || penB === undefined || penB === '') {
        showToast('Enter penalty scores for both teams!', 'warn'); return;
      }
      if (parseInt(penA) === parseInt(penB)) {
        showToast('Penalty scores cannot be equal — one team must win!', 'warn'); return;
      }
    }

    // Block if scores are equal but result type is not PSO
    if (sA !== null && sB !== null && parseInt(sA) === parseInt(sB)) {
      if (resultType !== 'PSO') {
        showToast('Draws must go to penalties (PSO)! Please select Penalties and enter penalty scores.', 'warn');
        return;
      }
    }

    setSaving(s => ({ ...s, [match.id]: true }));
    await saveMatch({ ...match, ...edits });
    setSaved(s => ({ ...s, [match.id]: true }));
    setSaving(s => ({ ...s, [match.id]: false }));
    setTimeout(() => setSaved(s => ({ ...s, [match.id]: false })), 2000);
    showToast(`Match #${match.matchNum} updated!`);
  };

  const handleDeleteMatch = async (matchId) => {
    if (!window.confirm('Are you sure you want to delete this match? All predictions for this match will also be deleted!')) return;
    try {
      const saved = localStorage.getItem('wc_user');
      const token = saved ? JSON.parse(saved).token : '';
      const res = await fetch(`${BASE_URL}/api/matches/${matchId}`, {
        method: 'DELETE',
        headers: { 'Authorization': `Bearer ${token}` }
      });
      if (!res.ok) throw new Error('Failed to delete match');
      showToast('Match deleted successfully');
      // Refresh matches
      window.location.reload();
    } catch (err) {
      alert(err.message);
    }
  };

  const roundMatches = matches.filter(m => m.round === activeRound);

  // ── ADD MATCH TAB ──
  const handleAddMatch = async () => {
    setMatchError('');
    if (!newMatch.teamAName.trim() || !newMatch.teamBName.trim()) { setMatchError('Both team names are required.'); return; }
    if (!newMatch.date) { setMatchError('Match date is required.'); return; }
    setMatchAdding(true);
    const id = `custom_${Date.now()}`;
    const num = newMatch.matchNum || (matches.filter(m => m.round === newMatch.round).length + 1);
    await addMatch({
      id,
      round: newMatch.round,
      matchNum: parseInt(num),
      date: newMatch.date,
      time: newMatch.time,
      venue: newMatch.venue,
      teamA: { name: newMatch.teamAName.trim(), flag: newMatch.teamAFlag },
      teamB: { name: newMatch.teamBName.trim(), flag: newMatch.teamBFlag },
      scoreA: null, scoreB: null, status: 'upcoming',
    });
    setNewMatch(emptyMatch);
    setMatchAdding(false);
    showToast('Match added successfully!');
    setActiveTab('scores');
    setActiveRound(newMatch.round);
  };

  const handleUpdateTeam = async () => {
    if (!editingTeam || !editingTeam.name) return;
    setTeamSaving(true);
    setTeamError('');
    try {
      await saveTeam(editingTeam.name, editingTeam);
      setEditingTeam(null);
      showToast(`Team ${editingTeam.name} updated!`);
    } catch (err) {
      setTeamError(err.message || 'Failed to update team.');
    } finally {
      setTeamSaving(false);
    }
  };

  const handleAddTeam = async () => {
    if (!newTeam.name.trim()) { setTeamError('Team name is required.'); return; }
    setTeamSaving(true);
    setTeamError('');
    try {
      await addTeam({
        name: newTeam.name.trim(),
        flag: newTeam.flag,
        group: newTeam.group
      });
      setNewTeam({ name: '', flag: '🏆', group: 'A' });
      showToast(`Team "${newTeam.name.trim()}" added!`);
    } catch (err) {
      setTeamError(err.message || 'Failed to add team.');
    } finally {
      setTeamSaving(false);
    }
  };

  const handleDeleteTeam = async (t) => {
    setTeamSaving(true);
    setTeamError('');
    try {
      await deleteTeam(t.name);
      setConfirmDeleteTeam(null);
      showToast(`Team "${t.name}" removed.`, 'warn');
    } catch (err) {
      setTeamError(err.message || 'Failed to delete team.');
    } finally {
      setTeamSaving(false);
    }
  };

  const handleReset = async () => {
    setConfirmReset(false);
    setEditing({});
    await resetMatches();
    showToast('All matches reset.', 'warn');
  };

  const getAvailableTeams = (round) => {
    let available = [...teams];
    const completedMatches = matches.filter(m => m.status === 'completed' && m.scoreA !== null && m.scoreB !== null);
    const roundIndex = ROUND_ORDER.indexOf(round);

    const eliminatedTeams = new Set();
    completedMatches.forEach(m => {
      const mRoundIndex = ROUND_ORDER.indexOf(m.round);
      if (mRoundIndex < roundIndex) {
        // For PSO matches, use penalty scores to determine winner
        if (m.resultType === 'PSO' && m.penaltyA !== null && m.penaltyB !== null) {
          if (m.penaltyA > m.penaltyB) eliminatedTeams.add(m.teamB.name);
          else eliminatedTeams.add(m.teamA.name);
        } else {
          if (m.scoreA > m.scoreB) eliminatedTeams.add(m.teamB.name);
          else if (m.scoreB > m.scoreA) eliminatedTeams.add(m.teamA.name);
        }
      }
    });

    const playingInRound = new Set();
    matches.filter(m => m.round === round).forEach(m => {
      if (m.teamA?.name) playingInRound.add(m.teamA.name);
      if (m.teamB?.name) playingInRound.add(m.teamB.name);
    });

    return available.filter(t => !eliminatedTeams.has(t.name) && !playingInRound.has(t.name));
  };

  return (
    <div className="page admin-page">
      {/* Toast */}
      {toast && <div className={`admin-toast admin-toast--${toast.type}`}>{toast.msg}</div>}

      {/* Confirm Reset */}
      {confirmReset && (
        <div className="confirm-overlay">
          <div className="confirm-box">
            <div className="confirm-icon">⚠️</div>
            <p>Reset all match results? This cannot be undone.</p>
            <div className="confirm-btns">
              <button className="btn-danger" onClick={handleReset}>Yes, Reset</button>
              <button className="btn-cancel" onClick={() => setConfirmReset(false)}>Cancel</button>
            </div>
          </div>
        </div>
      )}

      {/* Confirm Delete Team */}
      {confirmDeleteTeam && (
        <div className="confirm-overlay">
          <div className="confirm-box">
            <div className="confirm-icon">🗑️</div>
            <p>Delete team <strong>{confirmDeleteTeam.name}</strong> ({confirmDeleteTeam.flag})?</p>
            <div className="confirm-btns">
              <button className="btn-danger" onClick={() => handleDeleteTeam(confirmDeleteTeam)} disabled={teamSaving}>
                {teamSaving ? 'Deleting...' : 'Delete'}
              </button>
              <button className="btn-cancel" onClick={() => setConfirmDeleteTeam(null)}>Cancel</button>
            </div>
          </div>
        </div>
      )}

      {/* Insights Modal */}
      {insights && (
        <div className="confirm-overlay" onClick={() => setInsights(null)}>
          <div className="insights-modal" onClick={e => e.stopPropagation()}>
            <div className="insights-header">
              <h3>📊 Match Insights</h3>
              <button className="close-insights" onClick={() => setInsights(null)}>×</button>
            </div>
            <p className="insights-match-title">{insights.match.teamA.name} vs {insights.match.teamB.name}</p>
            
            <div className="insights-stats">
              <div className="stat-card">
                <span className="stat-value">{insights.data.totalPredictions}</span>
                <span className="stat-label">Total Predictions</span>
              </div>
            </div>

            <div className="insights-bars">
              <div className="bar-row">
                <span>{insights.match.teamA.name} Win</span>
                <div className="bar-track"><div className="bar-fill blue" style={{ width: (insights.data.totalPredictions ? (insights.data.teamAWin / insights.data.totalPredictions) * 100 : 0) + '%' }}></div></div>
                <span>{insights.data.teamAWin}</span>
              </div>
              <div className="bar-row">
                <span>Draw</span>
                <div className="bar-track"><div className="bar-fill gray" style={{ width: (insights.data.totalPredictions ? (insights.data.draw / insights.data.totalPredictions) * 100 : 0) + '%' }}></div></div>
                <span>{insights.data.draw}</span>
              </div>
              <div className="bar-row">
                <span>{insights.match.teamB.name} Win</span>
                <div className="bar-track"><div className="bar-fill green" style={{ width: (insights.data.totalPredictions ? (insights.data.teamBWin / insights.data.totalPredictions) * 100 : 0) + '%' }}></div></div>
                <span>{insights.data.teamBWin}</span>
              </div>
            </div>

            <h4 className="exact-scores-title">Most Common Exact Scores</h4>
            {insights.data.exactScores.length === 0 ? (
              <p className="no-scores">No exact scores predicted yet.</p>
            ) : (
              <ul className="exact-scores-list">
                {insights.data.exactScores.slice(0, 5).map((es, idx) => (
                  <li key={idx}>
                    <span className="es-score">{es.score}</span>
                    <span className="es-count">{es.count} {es.count === 1 ? 'prediction' : 'predictions'}</span>
                  </li>
                ))}
              </ul>
            )}
          </div>
        </div>
      )}

      {/* Header */}
      <div className="page-header">
        <div>
          <h2 className="page-title admin-title">⚙️ ADMIN PANEL</h2>
          <p className="page-sub">Manage matches, scores &amp; participants</p>
        </div>
        <button className="reset-btn" onClick={() => setConfirmReset(true)}>🔄 Reset All Scores</button>
      </div>

      {/* Main Tabs */}
      <div className="admin-tabs">
        {[['scores','🎛️','Match Control'], ['matches','➕','Add Match'], ['users','📊','Analytics'], ['teams','🏆','Manage Teams']].map(([key, icon, label]) => (
          <button key={key} className={`admin-tab-btn ${activeTab === key ? 'active' : ''}`} onClick={() => setActiveTab(key)}>
            <span className="atb-icon">{icon}</span>
            <span className="atb-label">{label}</span>
          </button>
        ))}
      </div>

      {/* ── SCORES TAB ── */}
      {activeTab === 'scores' && (
        <div className="tab-content">
          <div className="round-tabs">
            {ROUND_ORDER.map(r => (
              <button key={r} className={`round-tab ${activeRound === r ? 'active' : ''}`} onClick={() => setActiveRound(r)}>{r}</button>
            ))}
          </div>
          {loading ? (
            <div className="empty-state">Loading matches...</div>
          ) : (
            <div className="admin-matches">
              {roundMatches.length === 0 && <div className="empty-state">No matches in this round yet. Add one from the Add Match tab.</div>}
              {roundMatches.map(match => (
                <div key={match.id} className={`admin-match-card ${match.status}`}>
                  <div className="amc-header">
                    <span className="amc-id">Match #{match.matchNum} · {match.venue}</span>
                    <div className="status-btns">
                      {['upcoming','live','completed'].map(s => (
                        <button key={s} className={`status-btn ${(editing[match.id]?.status || match.status) === s ? 'active-' + s : ''}`} onClick={() => handleEdit(match.id, 'status', s)}>
                          {s === 'upcoming' ? '⏳' : s === 'live' ? '🔴' : '✅'} {s.toUpperCase()}
                        </button>
                      ))}
                    </div>
                  </div>
                  <div className="amc-teams">
                    <div className="amc-team">
                      <span className="amc-flag">{match.teamA.flag}</span>
                      <span className="amc-name">{match.teamA.name}</span>
                    </div>
                    <div className="amc-scores">
                      <input type="number" min="0" max="20" className="admin-score-input" value={getVal(match, 'scoreA')} onChange={e => handleEdit(match.id, 'scoreA', e.target.value === '' ? null : parseInt(e.target.value))} placeholder="—" />
                      <span className="amc-sep">:</span>
                      <input type="number" min="0" max="20" className="admin-score-input" value={getVal(match, 'scoreB')} onChange={e => handleEdit(match.id, 'scoreB', e.target.value === '' ? null : parseInt(e.target.value))} placeholder="—" />
                    </div>
                    <div className="amc-team right">
                      <span className="amc-name">{match.teamB.name}</span>
                      <span className="amc-flag">{match.teamB.flag}</span>
                    </div>
                  </div>
                  {/* Result Type — only for knockout rounds */}
                  <div className="amc-result-type">
                    <span className="amc-rt-label">Result:</span>
                    {[['90min','⏱ 90 min'],['ET','⚽ Extra Time'],['PSO','🥅 Penalties']].map(([val, label]) => (
                      <button
                        key={val}
                        className={`rt-btn ${
                          (editing[match.id]?.resultType ?? match.resultType ?? '90min') === val ? 'rt-active' : ''
                        }`}
                        onClick={() => handleEdit(match.id, 'resultType', val)}
                      >{label}</button>
                    ))}
                  </div>

                  {/* Penalty Scores — shown when PSO selected OR scores are a draw */}
                  {((editing[match.id]?.resultType ?? match.resultType) === 'PSO' || (getVal(match, 'scoreA') !== null && getVal(match, 'scoreA') === getVal(match, 'scoreB'))) && (
                    <div className="amc-penalty-row">
                      <span className="amc-pen-label">🥅 Penalties:</span>
                      <span className="amc-pen-team">{match.teamA.flag} {match.teamA.name}</span>
                      <input
                        type="number" min="0" max="20"
                        className="admin-score-input penalty-input"
                        value={getVal(match, 'penaltyA') ?? ''}
                        onChange={e => handleEdit(match.id, 'penaltyA', e.target.value === '' ? null : parseInt(e.target.value))}
                        placeholder="0"
                      />
                      <span className="amc-sep">–</span>
                      <input
                        type="number" min="0" max="20"
                        className="admin-score-input penalty-input"
                        value={getVal(match, 'penaltyB') ?? ''}
                        onChange={e => handleEdit(match.id, 'penaltyB', e.target.value === '' ? null : parseInt(e.target.value))}
                        placeholder="0"
                      />
                      <span className="amc-pen-team">{match.teamB.flag} {match.teamB.name}</span>
                    </div>
                  )}
                  <div className="amc-footer">
                    <div className="amc-date-edit" style={{ display: 'flex', alignItems: 'center', gap: '5px' }}>
                      <span title="Edit match date and time">📅</span>
                      <input 
                        type="date" 
                        value={editing[match.id]?.date ?? match.date ?? ''} 
                        onChange={e => handleEdit(match.id, 'date', e.target.value)} 
                        className="admin-score-input"
                        style={{ width: '130px', fontSize: '0.8rem', padding: '0.4rem' }}
                      />
                      <input 
                        type="time" 
                        value={editing[match.id]?.time ?? match.time ?? ''} 
                        onChange={e => handleEdit(match.id, 'time', e.target.value)} 
                        className="admin-score-input"
                        style={{ width: '100px', fontSize: '0.8rem', padding: '0.4rem' }}
                      />
                    </div>
                    <div className="amc-footer-actions">
                      <button className="amc-insights-btn" onClick={() => handleViewInsights(match)} disabled={loadingInsights}>📊 Insights</button>
                      <button 
                        className="amc-delete-btn" 
                        onClick={() => handleDeleteMatch(match.id)}
                        style={{ background: 'rgba(239, 68, 68, 0.1)', color: '#ef4444', border: '1px solid rgba(239, 68, 68, 0.3)', padding: '0.6rem 1rem', borderRadius: '8px', cursor: 'pointer', fontWeight: '600' }}
                      >
                        🗑️ Delete
                      </button>
                      <button
                        className={`amc-save-btn ${saved[match.id] ? 'saved' : ''}`}
                        onClick={() => handleSave(match)}
                        disabled={saving[match.id]}
                      >
                        {saving[match.id] ? 'Saving...' : saved[match.id] ? '✓ Saved!' : 'Save Match'}
                      </button>
                    </div>
                  </div>
                </div>
              ))}
            </div>
          )}
        </div>
      )}

      {/* ── ADD MATCH TAB ── */}
      {activeTab === 'matches' && (() => {
        const availableTeams = getAvailableTeams(newMatch.round);
        return (
          <div className="tab-content">
            <div className="add-match-form">
              <h3 className="form-section-title">➕ Add New Match</h3>
              <div className="form-grid">
                <div className="form-group">
                  <label>Round</label>
                  <select value={newMatch.round} onChange={e => setNewMatch(m => ({ ...m, round: e.target.value, teamAName: '', teamBName: '' }))}>
                    {ROUND_ORDER.map(r => <option key={r}>{r}</option>)}
                  </select>
                </div>
                <div className="form-group">
                  <label>Match Number</label>
                  <input type="number" placeholder="Auto" value={newMatch.matchNum} onChange={e => setNewMatch(m => ({ ...m, matchNum: e.target.value }))} />
                </div>
                <div className="form-group">
                  <label>Date</label>
                  <input type="date" value={newMatch.date} onChange={e => setNewMatch(m => ({ ...m, date: e.target.value }))} />
                </div>
                <div className="form-group">
                  <label>Time (local)</label>
                  <input type="time" value={newMatch.time} onChange={e => setNewMatch(m => ({ ...m, time: e.target.value }))} />
                </div>
                <div className="form-group full-width">
                  <label>Venue</label>
                  <select value={newMatch.venue} onChange={e => setNewMatch(m => ({ ...m, venue: e.target.value }))}>
                    {VENUES.map(v => <option key={v}>{v}</option>)}
                    <option value="custom">Other venue...</option>
                  </select>
                </div>
              </div>

              <div className="teams-row">
                <div className="team-entry">
                  <h4>Team A</h4>
                  <div className="form-group">
                    <label>Select Team A</label>
                    <select
                      value={newMatch.teamAName}
                      onChange={e => {
                        const selected = availableTeams.find(t => t.name === e.target.value);
                        setNewMatch(m => ({
                          ...m,
                          teamAName: e.target.value,
                          teamAFlag: selected ? selected.flag : '🏆'
                        }));
                      }}
                    >
                      <option value="">-- Select Team --</option>
                      {availableTeams.filter(t => t.name !== newMatch.teamBName).map(t => (
                        <option key={t.name} value={t.name}>{t.flag} {t.name}</option>
                      ))}
                    </select>
                  </div>
                </div>
                <div className="vs-divider">VS</div>
                <div className="team-entry">
                  <h4>Team B</h4>
                  <div className="form-group">
                    <label>Select Team B</label>
                    <select
                      value={newMatch.teamBName}
                      onChange={e => {
                        const selected = availableTeams.find(t => t.name === e.target.value);
                        setNewMatch(m => ({
                          ...m,
                          teamBName: e.target.value,
                          teamBFlag: selected ? selected.flag : '🏆'
                        }));
                      }}
                    >
                      <option value="">-- Select Team --</option>
                      {availableTeams.filter(t => t.name !== newMatch.teamAName).map(t => (
                        <option key={t.name} value={t.name}>{t.flag} {t.name}</option>
                      ))}
                    </select>
                  </div>
                </div>
              </div>

              {matchError && <div className="form-error">⚠️ {matchError}</div>}
              <button className="form-submit-btn" onClick={handleAddMatch} disabled={matchAdding}>
                {matchAdding ? 'Adding...' : '➕ Add Match'}
              </button>
            </div>

            {/* Existing matches list */}
            <div className="match-list-summary">
              <h3 className="form-section-title">📋 All Matches ({matches.length})</h3>
              <div className="match-summary-grid">
                {ROUND_ORDER.map(r => {
                  const rm = matches.filter(m => m.round === r);
                  if (rm.length === 0) return null;
                  return (
                    <div key={r} className="match-summary-round">
                      <div className="msr-header">{r} <span>({rm.length})</span></div>
                      {rm.map(m => (
                        <div key={m.id} className={`msr-row ${m.status}`}>
                          <span className="msr-flags">{m.teamA.flag} {m.teamB.flag}</span>
                          <span className="msr-name">{m.teamA.name} vs {m.teamB.name}</span>
                          <span className={`msr-status msr-${m.status}`}>{m.status === 'upcoming' ? '⏳' : m.status === 'live' ? '🔴' : '✅'}</span>
                          {m.scoreA !== null && <span className="msr-score">{m.scoreA}–{m.scoreB}</span>}
                        </div>
                      ))}
                    </div>
                  );
                })}
              </div>
            </div>
          </div>
        );
      })()}


      {/* ── ANALYTICS TAB ── */}
      {activeTab === 'users' && (
        <div className="tab-content">
          <div className="analytics-summary">
            <div className="stat-card">
              <h3>{users.length}</h3>
              <p>Total Registered</p>
            </div>
            <div className="stat-card">
              <h3>{users.filter(u => u.hasPredicted).length}</h3>
              <p>Active Predictors</p>
            </div>
            <div className="stat-card">
              <h3>{users.filter(u => !u.hasPredicted).length}</h3>
              <p>No Predictions Yet</p>
            </div>
          </div>

          <div className="users-list-section">
            <h3 className="form-section-title">👥 Participant Directory</h3>
            <div className="users-table">
              <div className="users-table-head" style={{ gridTemplateColumns: '50px 1.5fr 1fr 1fr 100px' }}>
                <span>#</span>
                <span>Name</span>
                <span>Admission No.</span>
                <span>Department</span>
                <span>Status</span>
              </div>
              {users.map((u, i) => (
                <div key={u.rollNumber} className="users-table-row" style={{ gridTemplateColumns: '50px 1.5fr 1fr 1fr 100px' }}>
                  <span className="ut-num">{i + 1}</span>
                  <span className="ut-name">{u.name}</span>
                  <span className="ut-roll">{u.rollNumber}</span>
                  <span className="ut-dept">{u.department}</span>
                  <span className="ut-status">{u.hasPredicted ? '✅ Active' : '❌ Pending'}</span>
                </div>
              ))}
            </div>
          </div>
        </div>
      )}

      {/* ── TEAMS TAB ── */}
      {activeTab === 'teams' && (
        <div className="tab-content">
          {/* Add team form */}
          <div className="add-user-form">
            <h3 className="form-section-title">🏆 Add New Team</h3>
            <div className="form-grid">
              <div className="form-group">
                <label>Team Name</label>
                <input placeholder="e.g. Italy" value={newTeam.name} onChange={e => setNewTeam(t => ({ ...t, name: e.target.value }))} />
              </div>
              <div className="form-group">
                <label>Team Logo / Flag Emoji</label>
                <input placeholder="e.g. 🇮🇹" value={newTeam.flag} onChange={e => setNewTeam(t => ({ ...t, flag: e.target.value }))} />
              </div>
              <div className="form-group">
                <label>Group</label>
                <input style={{ textTransform: 'uppercase' }} maxLength="1" placeholder="e.g. A" value={newTeam.group} onChange={e => setNewTeam(t => ({ ...t, group: e.target.value.toUpperCase() }))} />
              </div>
            </div>
            {teamError && <div className="form-error">⚠️ {teamError}</div>}
            <button className="form-submit-btn" onClick={handleAddTeam} disabled={teamSaving}>
              {teamSaving ? 'Adding...' : '➕ Add Team'}
            </button>
          </div>

          <div className="teams-list-section">
            <h3 className="form-section-title">📋 All Teams &amp; Standings ({teams.length})</h3>

            <div className="admin-teams-table" style={{ maxWidth: '600px' }}>
              <div className="teams-table-head" style={{ display: 'grid', gridTemplateColumns: '1.5fr 1fr 120px', gap: '1rem', textAlign: 'left', padding: '.5rem 1rem' }}>
                <span>Team</span>
                <span>Group</span>
                <span>Actions</span>
              </div>

              {(teams || []).map((t) => (
                <div key={t.name} className="teams-table-row" style={{ display: 'grid', gridTemplateColumns: '1.5fr 1fr 120px', gap: '1rem', alignItems: 'center', padding: '.65rem 1rem', borderTop: '1px solid rgba(255,255,255,.04)' }}>
                  {editingTeam?.name === t.name ? (
                    <>
                      <span className="team-cell-flag" style={{ display: 'flex', alignItems: 'center', gap: '.5rem' }}>
                        <input
                          type="text"
                          className="team-edit-small-input"
                          style={{ width: '40px', padding: '.2rem', textAlign: 'center' }}
                          value={editingTeam.flag}
                          onChange={e => setEditingTeam(et => ({ ...et, flag: e.target.value }))}
                        />
                        <strong>{t.name}</strong>
                      </span>
                      <span>
                        <input
                          type="text"
                          className="team-edit-small-input"
                          style={{ width: '60px', padding: '.2rem', textAlign: 'center' }}
                          value={editingTeam.group}
                          onChange={e => setEditingTeam(et => ({ ...et, group: e.target.value.toUpperCase() }))}
                        />
                      </span>
                      <div className="ut-actions">
                        <button className="ut-btn ut-save" onClick={handleUpdateTeam} disabled={teamSaving}>
                          {teamSaving ? '...' : '✓'}
                        </button>
                        <button className="ut-btn ut-cancel" onClick={() => setEditingTeam(null)}>✕</button>
                      </div>
                    </>
                  ) : (
                    <>
                      <span className="team-cell-flag" style={{ display: 'flex', alignItems: 'center', gap: '.5rem' }}>
                        <span style={{ fontSize: '1.3rem' }}>{t.flag}</span>
                        <strong>{t.name}</strong>
                      </span>
                      <span>Group {t.group}</span>
                      <div className="ut-actions">
                        <button className="ut-btn ut-edit" onClick={() => setEditingTeam({ ...t })}>✏️ Edit</button>
                        <button className="ut-btn ut-delete" onClick={() => setConfirmDeleteTeam(t)}>🗑️ Delete</button>
                      </div>
                    </>
                  )}
                </div>
              ))}
            </div>
          </div>
        </div>
      )}

      <div className="admin-note">
        <strong>📡 Score updates:</strong> Set status to "Completed" after entering scores so predictions are scored correctly.
      </div>
    </div>
  );
}
