import React, { createContext, useContext, useState, useEffect, useCallback, useRef } from 'react';
const BASE_URL = process.env.REACT_APP_API_URL || 'http://localhost:5000';

const MatchContext = createContext(null);

// ── Teams data (static, used for Teams page) ────────────────────────────────

function getToken() {
  const saved = localStorage.getItem('wc_user');
  if (saved) {
    try { return JSON.parse(saved).token; } catch(e) {}
  }
  return null;
}

const STATIC_TEAMS = [
  { name: 'France',      flag: '🇫🇷', group: 'A' },
  { name: 'Brazil',      flag: '🇧🇷', group: 'B' },
  { name: 'England',     flag: '🏴󠁧󠁢󠁥󠁮󠁧󠁿', group: 'C' },
  { name: 'Germany',     flag: '🇩🇪', group: 'D' },
  { name: 'Argentina',   flag: '🇦🇷', group: 'E' },
  { name: 'Spain',       flag: '🇪🇸', group: 'F' },
  { name: 'Portugal',    flag: '🇵🇹', group: 'G' },
  { name: 'Netherlands', flag: '🇳🇱', group: 'H' },
  { name: 'Mexico',      flag: '🇲🇽', group: 'A' },
  { name: 'Poland',      flag: '🇵🇱', group: 'B' },
  { name: 'Senegal',     flag: '🇸🇳', group: 'C' },
  { name: 'Japan',       flag: '🇯🇵', group: 'D' },
  { name: 'Ecuador',     flag: '🇪🇨', group: 'E' },
  { name: 'Morocco',     flag: '🇲🇦', group: 'F' },
  { name: 'Uruguay',     flag: '🇺🇾', group: 'G' },
  { name: 'USA',         flag: '🇺🇸', group: 'H' },
];

export const TEAMS = STATIC_TEAMS;


// ── Helper: convert DB row → frontend match object ────────────────────────
// score_a / score_b come from SQLite as null OR empty string for unset values
function toNum(val) {
  if (val === null || val === undefined || val === '') return null;
  const n = Number(val);
  return isNaN(n) ? null : n;
}

function dbRowToMatch(row) {
  return {
    id:         row.match_id,
    dbId:       row.id,
    round:      row.round,
    matchNum:   row.match_num,
    date:       row.match_date,
    time:       row.match_time,
    venue:      row.venue,
    teamA:      { name: row.team_a_name, flag: row.team_a_flag, code: (row.team_a_name || '').slice(0, 3).toUpperCase() },
    teamB:      { name: row.team_b_name, flag: row.team_b_flag, code: (row.team_b_name || '').slice(0, 3).toUpperCase() },
    scoreA:     toNum(row.score_a),
    scoreB:     toNum(row.score_b),
    status:     row.status,
    resultType: row.result_type || '90min',
    penaltyA:   toNum(row.penalty_a),
    penaltyB:   toNum(row.penalty_b),
  };
}

// ── Scoring ───────────────────────────────────────────────────────────────
export function computePoints(prediction, result) {
  if (!result || result.scoreA === null || result.scoreA === undefined) return 0;
  if (!prediction || prediction.scoreA === null || prediction.scoreA === undefined) return 0;
  const pA = Number(prediction.scoreA), pB = Number(prediction.scoreB);
  const rA = Number(result.scoreA),     rB = Number(result.scoreB);

  const exactScore  = (pA === rA && pB === rB);
  const predWinner  = pA > pB ? 'A' : pA < pB ? 'B' : 'D';
  const realWinner  = rA > rB ? 'A' : rA < rB ? 'B' : 'D';

  // ── PSO match scoring (5 / 3 / 2 / 0) ──────────────────────────────────
  if (result.resultType === 'PSO') {
    const ppA = prediction.predPenaltyA != null ? Number(prediction.predPenaltyA) : null;
    const ppB = prediction.predPenaltyB != null ? Number(prediction.predPenaltyB) : null;
    const rpA = result.penaltyA != null ? Number(result.penaltyA) : null;
    const rpB = result.penaltyB != null ? Number(result.penaltyB) : null;

    let hasCorrectPenaltyWinner = false;
    if (ppA !== null && ppB !== null && rpA !== null && rpB !== null) {
      const predPW = ppA > ppB ? 'A' : 'B';
      const realPW = rpA > rpB ? 'A' : 'B';
      if (predPW === realPW) hasCorrectPenaltyWinner = true;
    }

    if (exactScore) {
      if (hasCorrectPenaltyWinner && ppA === rpA && ppB === rpB) return 5;
      if (hasCorrectPenaltyWinner) return 3;
      return 2;
    }

    if (predWinner === realWinner) {
      if (hasCorrectPenaltyWinner) return 3;
      return 2;
    }

    return 0;
  }

  // ── Regular / ET match scoring (5 / 2 / 0) ──────────────────────────────
  if (exactScore) return 5;
  if (predWinner === realWinner) return 2;
  return 0;
}

// ── Provider ──────────────────────────────────────────────────────────────
export function MatchProvider({ children }) {
  const [matches,     setMatches]     = useState([]);
  const [predictions, setPredictions] = useState({});  // { matchId: { rollNumber: {scoreA, scoreB} } }
  const [teams,       setTeams]       = useState(STATIC_TEAMS);
  const [loading,     setLoading]     = useState(true);
  const pollRef = useRef(null);

  // ── Fetch teams from backend ───────────────────────────────────────────
  const fetchTeams = useCallback(async () => {
    try {
      const res = await fetch(`${BASE_URL}/api/teams`);
      const data = await res.json();
      const mapped = data.map(t => ({
        id: t.id,
        name: t.name,
        flag: t.flag,
        group: t.team_group
      }));
      setTeams(mapped);
    } catch (err) {
      console.error('Failed to fetch teams:', err);
    }
  }, []);

  // ── Fetch matches from backend ─────────────────────────────────────────
  const fetchMatches = useCallback(async () => {
    try {
      const res  = await fetch(`${BASE_URL}/api/matches`);
      const data = await res.json();
      const mappedMatches = data.map(dbRowToMatch);
      setMatches(prev => {
        if (JSON.stringify(prev) === JSON.stringify(mappedMatches)) return prev;
        return mappedMatches;
      });
    } catch (err) {
      console.error('Failed to fetch matches:', err);
    } finally {
      setLoading(false);
    }
  }, []);

  // ── Save or update team stats (admin) ──────────────────────────────────
  const saveTeam = useCallback(async (name, updatedStats) => {
    try {
      const res = await fetch(`${BASE_URL}/api/teams/${name}`, {
        method: 'PUT',
        headers: { 
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${getToken()}`
        },
        body: JSON.stringify({
          flag: updatedStats.flag,
          team_group: updatedStats.group
        }),
      });
      if (!res.ok) {
        const err = await res.json().catch(() => ({}));
        throw new Error(err.message || 'Failed to update team');
      }
      await fetchTeams();
    } catch (err) {
      console.error('Failed to update team:', err);
      throw err;
    }
  }, [fetchTeams]);

  // ── Add a new team (admin) ───────────────────────────────────────────
  const addTeam = useCallback(async (newTeam) => {
    try {
      const res = await fetch(`${BASE_URL}/api/teams`, {
        method:  'POST',
        headers: { 
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${getToken()}`
        },
        body: JSON.stringify({
          name:       newTeam.name,
          flag:       newTeam.flag || '🏆',
          team_group: newTeam.group || 'A'
        }),
      });
      if (!res.ok) {
        const err = await res.json().catch(() => ({}));
        throw new Error(err.message || 'Failed to add team');
      }
      await fetchTeams();
    } catch (err) {
      console.error('Failed to add team:', err);
      throw err;
    }
  }, [fetchTeams]);

  // ── Delete a team (admin) ────────────────────────────────────────────
  const deleteTeam = useCallback(async (name) => {
    try {
      const res = await fetch(`${BASE_URL}/api/teams/${name}`, {
        method:  'DELETE',
        headers: { 'Authorization': `Bearer ${getToken()}` }
      });
      if (!res.ok) {
        const err = await res.json().catch(() => ({}));
        throw new Error(err.message || 'Failed to delete team');
      }
      await fetchTeams();
    } catch (err) {
      console.error('Failed to delete team:', err);
      throw err;
    }
  }, [fetchTeams]);

  // ── On mount: load matches & teams + start polling every 30 s ──────────
  useEffect(() => {
    fetchMatches();
    fetchTeams();
    // Poll every 30 seconds so all clients see score/team updates
    pollRef.current = setInterval(() => {
      fetchMatches();
      fetchTeams();
    }, 30000);
    return () => clearInterval(pollRef.current);
  }, [fetchMatches, fetchTeams]);

  // ── Load predictions for a user ──────────────────────────────────────
  const fetchPredictionsForUser = useCallback(async (rollNumber) => {
    try {
      const res = await fetch(`${BASE_URL}/api/predictions/${rollNumber}`, {
        headers: { 'Authorization': `Bearer ${getToken()}` }
      });
      const data = await res.json();
      if (!Array.isArray(data)) return;
      const formatted = {};
      data.forEach(p => {
        if (!formatted[p.match_id]) formatted[p.match_id] = {};
        formatted[p.match_id][p.roll_number] = {
          scoreA:       toNum(p.score_a),
          scoreB:       toNum(p.score_b),
          predPenaltyA: toNum(p.pred_penalty_a),
          predPenaltyB: toNum(p.pred_penalty_b),
          createdAt:    p.created_at,
        };
      });
      setPredictions(prev => ({ ...prev, ...formatted }));
    } catch (err) {
      console.error('Failed to fetch predictions:', err);
    }
  }, []);

  // ── Save or update a match score (admin) ──────────────────────────────
  const saveMatch = useCallback(async (updatedMatch) => {
    try {
      const res = await fetch(`${BASE_URL}/api/matches/by-match-id/${updatedMatch.id}`, {
        method:  'PUT',
        headers: { 
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${getToken()}`
        },
        body: JSON.stringify({
          score_a:     updatedMatch.scoreA,
          score_b:     updatedMatch.scoreB,
          status:      updatedMatch.status,
          result_type: updatedMatch.resultType || '90min',
          penalty_a:   updatedMatch.penaltyA ?? null,
          penalty_b:   updatedMatch.penaltyB ?? null,
          match_date:  updatedMatch.date,
          match_time:  updatedMatch.time,
        }),
      });
      if (!res.ok) {
        const err = await res.json().catch(() => ({}));
        throw new Error(err.message || 'Failed to save match');
      }
      // Immediately refresh matches so all views update
      await fetchMatches();
    } catch (err) {
      console.error('Failed to save match:', err);
      throw err;
    }
  }, [fetchMatches]);

  // ── Add a new match (admin) ───────────────────────────────────────────
  const addMatch = useCallback(async (newMatch) => {
    try {
      await fetch(`${BASE_URL}/api/matches`, {
        method:  'POST',
        headers: { 
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${getToken()}`
        },
        body: JSON.stringify({
          match_id:    newMatch.id,
          round:       newMatch.round,
          match_num:   newMatch.matchNum,
          match_date:  newMatch.date,
          match_time:  newMatch.time,
          venue:       newMatch.venue,
          team_a_name: newMatch.teamA.name,
          team_a_flag: newMatch.teamA.flag,
          team_b_name: newMatch.teamB.name,
          team_b_flag: newMatch.teamB.flag,
        }),
      });
      await fetchMatches();
    } catch (err) {
      console.error('Failed to add match:', err);
    }
  }, [fetchMatches]);

  // ── Reset all match scores (admin) ────────────────────────────────────
  const resetMatches = useCallback(async () => {
    try {
      const res  = await fetch(`${BASE_URL}/api/matches`);
      const data = await res.json();
      for (const row of data) {
        await fetch(`${BASE_URL}/api/matches/by-match-id/${row.match_id}`, {
          method:  'PUT',
          headers: { 
            'Content-Type': 'application/json',
            'Authorization': `Bearer ${getToken()}`
          },
          body: JSON.stringify({ score_a: null, score_b: null, status: 'upcoming' }),
        });
      }
      await fetchMatches();
    } catch (err) {
      console.error('Failed to reset matches:', err);
    }
  }, [fetchMatches]);

  // ── Save a prediction ─────────────────────────────────────────────────
  const savePrediction = useCallback(async (rollNumber, matchId, scoreA, scoreB, predPenaltyA, predPenaltyB) => {
    const sA = parseInt(scoreA, 10);
    const sB = parseInt(scoreB, 10);
    const ppA = predPenaltyA !== '' && predPenaltyA != null ? parseInt(predPenaltyA, 10) : null;
    const ppB = predPenaltyB !== '' && predPenaltyB != null ? parseInt(predPenaltyB, 10) : null;
    try {
      await fetch(`${BASE_URL}/api/predictions`, {
        method:  'POST',
        headers: { 
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${getToken()}`
        },
        body: JSON.stringify({ rollNumber, matchId, scoreA: sA, scoreB: sB, predPenaltyA: ppA, predPenaltyB: ppB }),
      });
      // Optimistic local update for instant feedback
      setPredictions(prev => ({
        ...prev,
        [matchId]: {
          ...(prev[matchId] || {}),
          [rollNumber]: { scoreA: sA, scoreB: sB, predPenaltyA: ppA, predPenaltyB: ppB },
        },
      }));
    } catch (err) {
      console.error('Failed to save prediction:', err);
    }
  }, []);

  // ── Get a user's prediction (from local state) ───────────────────────
  const getUserPrediction = useCallback((rollNumber, matchId) => {
    return predictions[matchId]?.[rollNumber] || null;
  }, [predictions]);

  // ── Compute leaderboard locally (for offline use / fallback) ─────────
  const getLeaderboard = useCallback((users) => {
    return (users || [])
      .filter(u => !u.isAdmin)
      .map(u => {
        let points = 0, correct = 0, exactScores = 0, lastPredictionTime = 0;
        const times = [];
        
        matches.forEach(m => {
          if (m.status === 'completed' && m.scoreA !== null) {
            const pred = predictions[m.id]?.[u.rollNumber];
            if (pred) {
              const p = computePoints(pred, m);
              points += p;
              if (p >= 2) correct++;
              if (p === 5) exactScores++;
            }
          }
        });
        
        // Find latest prediction time from all available predictions for this user
        Object.values(predictions).forEach(matchPreds => {
            const userPred = matchPreds[u.rollNumber];
            if (userPred && userPred.createdAt) {
                const t = new Date(userPred.createdAt).getTime();
                if (!isNaN(t)) times.push(t);
            }
        });
        if (times.length > 0) {
            lastPredictionTime = Math.max(...times);
        }

        return { ...u, points, correct, exactScores, lastPredictionTime };
      })
      .sort((a, b) => {
        if (b.points !== a.points) return b.points - a.points;
        if (b.exactScores !== a.exactScores) return b.exactScores - a.exactScores;
        return a.lastPredictionTime - b.lastPredictionTime;
      });
  }, [matches, predictions]);

  return (
    <MatchContext.Provider value={{
      matches, predictions, teams, loading,
      saveMatch, addMatch, resetMatches,
      savePrediction, getUserPrediction,
      getLeaderboard, fetchMatches, fetchPredictionsForUser,
      saveTeam, fetchTeams, addTeam, deleteTeam
    }}>
      {children}
    </MatchContext.Provider>
  );
}

export const useMatches = () => useContext(MatchContext);
