import React, { useState, useEffect, useCallback } from 'react';
import { useAuth } from '../context/AuthContext';
import { useMatches, computePoints } from '../context/MatchContext';
import html2canvas from 'html2canvas';
import './RankingPage.css';
const BASE_URL = process.env.REACT_APP_API_URL || 'http://localhost:5000';

export default function RankingPage() {
  const { user } = useAuth();
  const { matches, fetchMatches, loading: matchLoading } = useMatches();
  const [expandedUser, setExpandedUser]   = useState(null);
  const [leaderboard,  setLeaderboard]    = useState([]);
  const [lbLoading,    setLbLoading]      = useState(true);
  const [loadingMore,  setLoadingMore]    = useState(false);
  const [allPredictions, setAllPredictions] = useState({});
  const [currentPage,  setCurrentPage]    = useState(1);
  const [totalPages,   setTotalPages]     = useState(1);
  const [totalCount,   setTotalCount]     = useState(0);
  const [myRankData,   setMyRankData]     = useState(null);
  const [searchQuery,  setSearchQuery]    = useState('');
  const [debouncedSearch, setDebouncedSearch] = useState('');
  const [deptFilter,   setDeptFilter]     = useState('All');
  const [departments,  setDepartments]    = useState(['All']);
  const [deptOpen,     setDeptOpen]       = useState(false);
  const PAGE_LIMIT = 100;

  // Debounce search
  useEffect(() => {
    const timer = setTimeout(() => setDebouncedSearch(searchQuery), 300);
    return () => clearTimeout(timer);
  }, [searchQuery]);

  // Fetch departments list
  useEffect(() => {
    fetch(`${BASE_URL}/api/leaderboard/departments`)
      .then(r => r.json())
      .then(data => setDepartments(['All', ...data]))
      .catch(console.error);
  }, []);

  // ── Fetch leaderboard from backend (paginated + filtered) ─────────────────
  const fetchLeaderboard = useCallback(async (page = 1, append = false, search = '', dept = 'All') => {
    if (page === 1) setLbLoading(true);
    else setLoadingMore(true);
    try {
      const url = `${BASE_URL}/api/leaderboard?page=${page}&limit=${PAGE_LIMIT}&search=${encodeURIComponent(search)}&department=${encodeURIComponent(dept)}`;
      const res  = await fetch(url);
      const json = await res.json();
      const rows = json.data || [];
      setLeaderboard(prev => append ? [...prev, ...rows] : rows);
      setCurrentPage(json.page || 1);
      setTotalPages(json.totalPages || 1);
      setTotalCount(json.total || 0);
    } catch (err) {
      console.error('Failed to fetch leaderboard:', err);
    } finally {
      setLbLoading(false);
      setLoadingMore(false);
    }
  }, []);

  // ── Fetch this student's precise rank from backend ────────────────────
  const fetchMyRank = useCallback(async () => {
    if (!user?.rollNumber || user?.isAdmin) return;
    try {
      const res  = await fetch(`${BASE_URL}/api/leaderboard/my-rank/${user.rollNumber}`);
      const data = await res.json();
      setMyRankData(data);
    } catch (err) {
      console.error('Failed to fetch my rank:', err);
    }
  }, [user]);

  // ── On mount: get fresh match data then leaderboard ────────────────────
  useEffect(() => {
    const init = async () => {
      await fetchMatches();
      await fetchMyRank();
    };
    init();
  }, [fetchMatches, fetchMyRank]);

  // Fetch leaderboard when filters change or match data finishes loading
  useEffect(() => {
    if (!matchLoading && matches.length > 0) {
      fetchLeaderboard(1, false, debouncedSearch, deptFilter);
      fetchMyRank(); // ensure myRank refreshes if matches update
    }
  }, [debouncedSearch, deptFilter, matches, matchLoading, fetchLeaderboard, fetchMyRank]);

  const handleLoadMore = () => {
    if (currentPage < totalPages && !loadingMore) {
      fetchLeaderboard(currentPage + 1, true, debouncedSearch, deptFilter);
    }
  };

  // ── Load a specific user's predictions on expand ───────────────────────
  useEffect(() => {
    if (!expandedUser || allPredictions[expandedUser]) return;
    
    const saved = localStorage.getItem('wc_user');
    const token = saved ? JSON.parse(saved).token : '';

    fetch(`${BASE_URL}/api/predictions/${expandedUser}`, {
      headers: { 'Authorization': `Bearer ${token}` }
    })
      .then(r => r.json())
      .then(data => {
        if (!Array.isArray(data)) return;
        const map = {};
        data.forEach(p => {
          const sA = (p.score_a !== null && p.score_a !== '') ? Number(p.score_a) : null;
          const sB = (p.score_b !== null && p.score_b !== '') ? Number(p.score_b) : null;
          const pA = (p.pred_penalty_a !== null && p.pred_penalty_a !== '') ? Number(p.pred_penalty_a) : null;
          const pB = (p.pred_penalty_b !== null && p.pred_penalty_b !== '') ? Number(p.pred_penalty_b) : null;
          map[p.match_id] = { scoreA: sA, scoreB: sB, predPenaltyA: pA, predPenaltyB: pB };
        });
        setAllPredictions(prev => ({ ...prev, [expandedUser]: map }));
      })
      .catch(console.error);
  }, [expandedUser, allPredictions]);

  const completedMatches = matches.filter(m => m.status === 'completed');
  // Use backend-computed rank — works even when the user is not in the loaded page
  const myRank = myRankData?.rank || null;

  // My stats derived from myRankData
  const myStats = myRankData ? {
    rank:   myRankData.rank,
    points: myRankData.points,
    total:  myRankData.totalCount,
    me:     leaderboard.find(u => u.rollNumber === user?.rollNumber),
  } : null;

  const getUserMatchDetails = (rollNumber) => {
    const preds = allPredictions[rollNumber] || {};
    return matches.map(m => {
      const pred = preds[m.id] || null;
      const pts  = (m.status === 'completed' && m.scoreA !== null && pred)
        ? computePoints(pred, m)
        : null;
      return { ...m, pred, pts };
    });
  };

  const getMedalEmoji = (rank) => {
    if (rank === 1) return '🥇';
    if (rank === 2) return '🥈';
    if (rank === 3) return '🥉';
    return null;
  };

  const handleExportPNG = async () => {
    const element = document.getElementById('leaderboard-export-container');
    if (element) {
      // Temporarily expand all for export, or just export as is. We will export as is.
      const canvas = await html2canvas(element, { backgroundColor: '#0f172a', scale: 2 });
      const data = canvas.toDataURL('image/png');
      const link = document.createElement('a');
      link.href = data;
      link.download = `Leaderboard-${new Date().toISOString().split('T')[0]}.png`;
      document.body.appendChild(link);
      link.click();
      document.body.removeChild(link);
    }
  };

  const isLoading = lbLoading || matchLoading;

  return (
    <div className="page ranking-page">
      <div className="page-header">
        <div>
          <h2 className="page-title">LEADERBOARD</h2>
          <p className="page-sub">
            {completedMatches.length} match{completedMatches.length !== 1 ? 'es' : ''} completed · Rankings update live
          </p>
        </div>
        <div className="header-actions">
          {!user?.isAdmin && (
            <div className="my-rank-badge">
              <span className="rank-label">YOUR RANK</span>
              <span className="rank-num">{myRank ? `#${myRank}` : '—'}</span>
              <span className="rank-of">of {myRankData?.totalCount || totalCount} · {myRankData?.points ?? 0} pts</span>
            </div>
          )}
          {user?.isAdmin && (
            <button className="export-btn" onClick={handleExportPNG}>
              📸 Export as PNG
            </button>
          )}
        </div>
      </div>

      {/* ── MY STATS CARD (students only) ── */}
      {!user?.isAdmin && myStats && (
        <div className="my-stats-card">
          <div className="msc-avatar">{user?.name?.charAt(0)?.toUpperCase() || '?'}</div>
          <div className="msc-info">
            <span className="msc-name">{user?.name}</span>
            <span className="msc-dept">{myStats.me?.department || ''}</span>
          </div>
          <div className="msc-stat">
            <span className="msc-val">{myStats.rank ? `#${myStats.rank}` : '—'}</span>
            <span className="msc-lbl">Rank</span>
          </div>
          <div className="msc-divider"/>
          <div className="msc-stat">
            <span className="msc-val">{myStats.points}</span>
            <span className="msc-lbl">Points</span>
          </div>
          <div className="msc-divider"/>
          <div className="msc-stat">
            <span className="msc-val">{myStats.me?.exactScores ?? 0}</span>
            <span className="msc-lbl">Exact Scores</span>
          </div>
          <div className="msc-divider"/>
          <div className="msc-stat">
            <span className="msc-val">
              {myStats.me?.totalPredictions > 0
                ? `${Math.round((myStats.me.correct / myStats.me.totalPredictions) * 100)}%`
                : '0%'}
            </span>
            <span className="msc-lbl">Win Rate</span>
          </div>
        </div>
      )}

      {/* ── SEARCH + FILTER BAR ── */}
      {!isLoading && leaderboard.length > 0 && (
        <div className="lb-filter-bar">
          <div className="lb-search-wrap">
            <span className="lb-search-icon">🔍</span>
            <input
              className="lb-search-input"
              type="text"
              placeholder="Search by name or roll number..."
              value={searchQuery}
              onChange={e => setSearchQuery(e.target.value)}
            />
            {searchQuery && (
              <button className="lb-search-clear" onClick={() => setSearchQuery('')}>✕</button>
            )}
          </div>
          <div className="lb-custom-select">
            <div
              className={`lb-select-trigger ${deptOpen ? 'open' : ''}`}
              onClick={() => setDeptOpen(o => !o)}
            >
              <span className="lb-select-icon">🏫</span>
              <span style={{ flex: 1 }}>{deptFilter === 'All' ? 'All Departments' : deptFilter}</span>
              <span className="lb-select-arrow">▼</span>
            </div>
            {deptOpen && (
              <div className="lb-select-menu">
                {departments.map(d => (
                  <div
                    key={d}
                    className={`lb-select-option ${deptFilter === d ? 'selected' : ''}`}
                    onClick={() => { setDeptFilter(d); setDeptOpen(false); }}
                  >
                    {d === 'All' ? '🌍 All Departments' : d}
                  </div>
                ))}
              </div>
            )}
          </div>
        </div>
      )}

      {isLoading ? (
        <div className="lb-skeleton-list">
          {[...Array(8)].map((_, i) => (
            <div key={i} className="lb-skeleton-row">
              <div className="skel skel-rank"/>
              <div className="skel skel-avatar"/>
              <div className="skel-info">
                <div className="skel skel-name"/>
                <div className="skel skel-dept"/>
              </div>
              <div className="skel skel-pts"/>
            </div>
          ))}
        </div>
      ) : leaderboard.length === 0 ? (
        <div className="empty-state">
          {searchQuery || deptFilter !== 'All' ? 'No results match your search.' : 'No participants yet.'}
        </div>
      ) : (
        <div id="leaderboard-export-container" className="leaderboard-list">
          {leaderboard.map((u) => {
            // Rank directly from the server's window function
            const rank       = u.globalRank;
            const isMe       = u.rollNumber === user?.rollNumber;
            const medal      = getMedalEmoji(rank);
            const isExpanded = expandedUser === u.rollNumber;
            const matchDetails = isExpanded ? getUserMatchDetails(u.rollNumber) : [];

            return (
              <div key={u.rollNumber} className={`lb-row ${isMe ? 'is-me' : ''} ${rank <= 3 ? `top-${rank}` : ''}`}>
                <div className="lb-main" onClick={() => setExpandedUser(isExpanded ? null : u.rollNumber)}>
                  <div className="lb-rank">
                    {medal ? <span className="medal">{medal}</span> : rank}
                  </div>

                  <div className="lb-avatar">
                    {u.name.charAt(0).toUpperCase()}
                  </div>

                  <div className="lb-info">
                    <span className="lb-name">{u.name} {isMe && <span className="you-tag">YOU</span>}</span>
                    <span className="lb-dept">{u.department} • {u.year}</span>
                  </div>

                  <div className="lb-total-points-preview">
                    <span className="preview-val">{u.points}</span>
                    <span className="preview-lbl">PTS</span>
                  </div>

                  <span className="lb-expand">{isExpanded ? '▲' : '▼'}</span>
                </div>

                {isExpanded && (
                  <div className="lb-details fade-in">
                    <div className="lb-summary-stats">
                      <div className="stat-box"><span className="stat-b-val">{u.points}</span><span className="stat-b-lbl">Total Points</span></div>
                      <div className="stat-box"><span className="stat-b-val">{u.totalPredictions}</span><span className="stat-b-lbl">Predictions</span></div>
                      <div className="stat-box"><span className="stat-b-val">{u.exactScores}</span><span className="stat-b-lbl">Exact Scores</span></div>
                      <div className="stat-box"><span className="stat-b-val">{u.correct}</span><span className="stat-b-lbl">Wins/Draws</span></div>
                    </div>

                    <div className="lb-detail-header">
                      <span>MATCH</span>
                      <span>PREDICTION</span>
                      <span>RESULT</span>
                      <span>PTS</span>
                    </div>
                    {matchDetails.map(m => (
                      <div key={m.id} className={`lb-detail-row ${m.status}`}>
                        <span className="lb-match-name">
                          {m.teamA.flag} {m.teamA.name} vs {m.teamB.name} {m.teamB.flag}
                          <small>{m.round}</small>
                        </span>
                        <span className="lb-pred-val">
                          {m.pred ? `${m.pred.scoreA}–${m.pred.scoreB}${m.pred.predPenaltyA != null ? ` (${m.pred.predPenaltyA}-${m.pred.predPenaltyB} p)` : ''}` : '—'}
                        </span>
                        <span className="lb-result-val">
                          {m.status === 'completed' && m.scoreA !== null
                            ? `${m.scoreA}–${m.scoreB}${m.resultType === 'PSO' && m.penaltyA != null ? ` (${m.penaltyA}-${m.penaltyB} p)` : ''}`
                            : m.status === 'live' ? '🔴 LIVE' : '—'}
                        </span>
                        <span className={`lb-pts-val pts-${m.pts}`}>
                          {m.pts === null ? '—' : m.pts === 5 ? '+5 🎯' : m.pts === 3 ? '+3 ⚽' : m.pts === 2 ? '+2 ✅' : '0 ❌'}
                        </span>
                      </div>
                    ))}
                  </div>
                )}
              </div>
            );
          })}
        </div>
      )}

      {/* Load More Button */}
      {!lbLoading && leaderboard.length > 0 && currentPage < totalPages && (
        <div className="load-more-container">
          <button
            className="load-more-btn"
            onClick={handleLoadMore}
            disabled={loadingMore}
          >
            {loadingMore ? '⏳ Loading...' : `⬇ Load More — showing ${leaderboard.length} of ${totalCount} participants`}
          </button>
        </div>
      )}
      {!lbLoading && leaderboard.length > 0 && currentPage >= totalPages && (
        <p className="all-loaded-note">All {totalCount} participants loaded</p>
      )}

      <div className="scoring-legend">
        <h4>SCORING RULES</h4>
        <div className="legend-items">
          <div className="legend-item"><span className="leg-pts gold">+5</span><span>Exact score (includes perfect PSO)</span></div>
          <div className="legend-item"><span className="leg-pts blue">+3</span><span>Correct draw + correct PSO winner</span></div>
          <div className="legend-item"><span className="leg-pts green">+2</span><span>Correct winner / correct draw</span></div>
          <div className="legend-item"><span className="leg-pts red">0</span><span>Wrong prediction</span></div>
        </div>
        <p className="tiebreak-note">Tiebreaker: most exact scores → then earliest final prediction time</p>
      </div>
    </div>
  );
}
