import React, { useState } from 'react';
import { NavLink, useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import './Navbar.css';

export default function Navbar() {
  const { user, logout, USE_BACKEND } = useAuth();
  const navigate = useNavigate();
  const [open, setOpen] = useState(false);
  const [showUserMenu, setShowUserMenu] = useState(false);

  const handleLogout = () => {
    logout();
    navigate('/login');
    setShowUserMenu(false);
  };

  return (
    <nav className="navbar">
      <div className="navbar-brand">
        <span className="brand-trophy">🏆</span>
        <div className="brand-text">
          <span className="brand-main">WORLD CUP</span>
          <span className="brand-sub">2026 PREDICTION LEAGUE</span>
        </div>
        {USE_BACKEND && <span className="api-indicator" title="Backend connected">🟢</span>}
      </div>

      <div className={`navbar-links ${open ? 'open' : ''}`}>
        <NavLink to="/predict" className={({isActive}) => isActive ? 'nav-link active' : 'nav-link'} onClick={() => setOpen(false)}>
          PREDICT
        </NavLink>
        <NavLink to="/teams" className={({isActive}) => isActive ? 'nav-link active' : 'nav-link'} onClick={() => setOpen(false)}>
          TEAMS
        </NavLink>
        <NavLink to="/ranking" className={({isActive}) => isActive ? 'nav-link active' : 'nav-link'} onClick={() => setOpen(false)}>
          RANKINGS
        </NavLink>
        {user?.isAdmin && (
          <NavLink to="/admin" className={({isActive}) => isActive ? 'nav-link active admin-link' : 'nav-link admin-link'} onClick={() => setOpen(false)}>
            ADMIN
          </NavLink>
        )}
      </div>

      <div className="navbar-user" style={{ position: 'relative' }}>
        <button
          className="user-badge-btn"
          onClick={() => setShowUserMenu(m => !m)}
          title="Account options"
        >
          <div className="user-badge">
            <span className="user-name">{user?.name}</span>
            <span className="user-roll">{user?.isAdmin ? 'ADMIN' : '#' + user?.rollNumber}</span>
          </div>
          <span className="user-chevron">{showUserMenu ? '▲' : '▼'}</span>
        </button>

        {showUserMenu && (
          <div className="user-dropdown">
            {!user?.isAdmin && (
              <NavLink
                to="/change-password"
                className="user-dropdown-item"
                onClick={() => { setShowUserMenu(false); setOpen(false); }}
              >
                🎓 My Profile
              </NavLink>
            )}
            <button className="user-dropdown-item user-dropdown-logout" onClick={handleLogout}>
              ↩ Sign Out
            </button>
          </div>
        )}
      </div>

      <button className="hamburger" onClick={() => setOpen(o => !o)}>
        <span /><span /><span />
      </button>
    </nav>
  );
}
